SET NAMES utf8mb4;
DROP TABLE IF EXISTS plots;
CREATE TABLE plots(
 id INT PRIMARY KEY, city VARCHAR(80), city_en VARCHAR(80), project VARCHAR(255), zone_id INT,
 block VARCHAR(120), plot INT, area DECIMAL(10,2), base_per_m DECIMAL(12,2), corner DECIMAL(12,2), garden DECIMAL(12,2),
 sea DECIMAL(12,2), total_per_m DECIMAL(12,2), total_price DECIMAL(14,2), down_payment DECIMAL(14,2),
 has_premium TINYINT, map_file VARCHAR(40),
 INDEX(city), INDEX(zone_id), INDEX(total_per_m), INDEX(area), INDEX(total_price)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
